// Union tiplərinin sintaksisi
let value: string | number;
value = 'Hello';
console.log(value); // Hello
value = 42;
console.log(value); // 42
// value = true; // Xəta: boolean string | number tipinə təyin edilə bilməz

// Literal tiplərlə union tiplər
type Status = 'active' | 'inactive' | 'pending';
let userStatus: Status;
userStatus = 'active';
console.log(userStatus); // active
userStatus = 'pending';
console.log(userStatus); // pending
// userStatus = 'deleted'; // Xəta: 'deleted' Status tipinə təyin edilə bilməz

// Obyektlərlə union tiplər
interface Car {
  type: 'car';
  brand: string;
}

interface Bike {
  type: 'bike';
  hasGears: boolean;
}

type Vehicle = Car | Bike;

let vehicle: Vehicle;
vehicle = { type: 'car', brand: 'Toyota' };
console.log(vehicle); // { type: 'car', brand: 'Toyota' }
vehicle = { type: 'bike', hasGears: true };
console.log(vehicle); // { type: 'bike', hasGears: true }
// vehicle = { type: 'car', hasGears: true }; // Xəta: uyğun tip yoxdur

// Funksiyalarda union tiplər
function processInput(input: string | number): string {
  if (typeof input === 'string') {
    return input.toUpperCase();
  }
  return `Number: ${input}`;
}

console.log(processInput('hello')); // HELLO
console.log(processInput(42)); // Number: 42
// console.log(processInput(true)); // Xəta: boolean string | number tipinə təyin edilə bilməz

// Type narrowing
function describeValue(value: string | number | boolean): string {
  if (typeof value === 'string') {
    return `String: ${value}`;
  } else if (typeof value === 'number') {
    return `Number: ${value}`;
  }
  return `Boolean: ${value}`;
}

console.log(describeValue('test')); // String: test
console.log(describeValue(123)); // Number: 123
console.log(describeValue(true)); // Boolean: true

// Discriminated unions
interface ErrorResponse {
  type: 'error';
  message: string;
}

interface SuccessResponse {
  type: 'success';
  data: string;
}

type Response = ErrorResponse | SuccessResponse;

function handleResponse(response: Response): string {
  switch (response.type) {
    case 'success':
      return `Success: ${response.data}`;
    case 'error':
      return `Error: ${response.message}`;
  }
}

let success: Response = { type: 'success', data: 'Completed' };
let error: Response = { type: 'error', message: 'Failed' };

console.log(handleResponse(success)); // Success: Completed
console.log(handleResponse(error)); // Error: Failed

// Praktik nümunə
type ID = string | number;

interface User {
  id: ID;
  name: string;
}

function getUserInfo(user: User): string {
  return `ID: ${user.id}, Name: ${user.name}`;
}

let user1: User = { id: 1, name: 'Ali' };
let user2: User = { id: 'abc123', name: 'Vəli' };

console.log(getUserInfo(user1)); // ID: 1, Name: Ali
console.log(getUserInfo(user2)); // ID: abc123, Name: Vəli

// Təhlükəsizlik nümunəsi
function safeProcess(value: string | number): string {
  if (typeof value === 'string') {
    return value.toUpperCase();
  }
  return value.toString();
}

console.log(safeProcess('test')); // TEST
console.log(safeProcess(123)); // 123
// console.log(safeProcess(true)); // Xəta: boolean string | number tipinə təyin edilə bilməz

// Səhvə yol açan nümunə
let unsafe: any = 'test';
console.log(unsafe.toUpperCase()); // TEST
unsafe = 123;
console.log(unsafe.toUpperCase()); // Runtime xətası: toUpperCase number-də yoxdur

// Düzgün yol
let safe: string | number = 'test';
if (typeof safe === 'string') {
  console.log(safe.toUpperCase()); // TEST
}
safe = 123;
if (typeof safe === 'string') {
  console.log(safe.toUpperCase()); // Çalışmayacaq, xəta yoxdur
} else {
  console.log(safe); // 123
}

// Real layihə ssenarisi
interface TextMessage {
  type: 'text';
  content: string;
}

interface ImageMessage {
  type: 'image';
  url: string;
}

type Message = TextMessage | ImageMessage;

function displayMessage(message: Message): string {
  switch (message.type) {
    case 'text':
      return `Text: ${message.content}`;
    case 'image':
      return `Image: ${message.url}`;
  }
}

let textMsg: Message = { type: 'text', content: 'Hello!' };
let imageMsg: Message = { type: 'image', url: 'image.jpg' };

console.log(displayMessage(textMsg)); // Text: Hello!
console.log(displayMessage(imageMsg)); // Image: image.jpg

